def solve(s: String): Array[String] = {
    val segments = scala.collection.mutable.ArrayBuffer.empty[String]
    val seen = scala.collection.mutable.Set.empty[String]
    var i = 0
    val n = s.length
    while (i < n) {
        var current = ""
        var j = i
        var found = false
        while (j < n && !found) {
            current += s(j)
            if (!seen.contains(current)) {
                seen += current
                segments += current
                i = j + 1
                found = true
            }
            j += 1
        }
        if (!found) {
            i = j
        }
    }
    segments.toArray
}
